import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





const StepIndicator = ({ current, total }: { current: number; total: number }) => (
  <Stack gap="var(--ggui-spacing-2)">
    <Row justify="between" align="center">
      <Text variant="label">Step {current} of {total}</Text>
      <Text variant="label">{Math.round((current / total) * 100)}%</Text>
    </Row>
    <Progress value={current} max={total} size="sm" />
  </Stack>
);

const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: ''
  });
  const [emailError, setEmailError] = useState('');

  const isStepValid = useMemo(() => {
    if (step === 1) return !!formData.name && !!formData.email && isValidEmail(formData.email);
    if (step === 2) return formData.satisfaction > 0;
    if (step === 3) return formData.features.length > 0;
    return true;
  }, [step, formData.name, formData.email, formData.satisfaction, formData.features]);


  const handleNext = () => setStep((s) => Math.min(s + 1, 5));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const submitAction = useAction<ActionSubmitPayload>('submit');
  const handleSubmit = () => submitAction({
    name: formData.name,
    email: formData.email,
    satisfaction: formData.satisfaction,
    features: formData.features,
    comments: formData.comments
  });

  const updateField = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (field === 'email' && emailError) setEmailError('');
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {step <= 4 && <StepIndicator current={step} total={4} />}


        {step === 1 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Personal Information</Heading>
            <Input 
              label="Name" 
              value={formData.name} 
              onChange={(v) => updateField('name', v)} 
              required 
            />
            <Input 
              label="Email" 
              type="email" 
              value={formData.email} 
              onChange={(v) => updateField('email', v)} 
              error={emailError} 
              onBlur={() => !isValidEmail(formData.email) && setEmailError('Invalid email format')} 
              required 
            />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Satisfaction</Heading>
            <RadioGroup
              label="How satisfied are you?"
              value={formData.satisfaction.toString()}
              onChange={(v) => updateField('satisfaction', parseInt(v))}
              options={props.satisfactionLabels.map((l, i) => ({ value: (i + 1).toString(), label: l }))}
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Interests</Heading>
            <Stack gap="var(--ggui-spacing-2)">
              {props.featureOptions.map((f) => (
                <Checkbox
                  key={f}
                  label={f}
                  checked={formData.features.includes(f)}
                  onChange={(c) => updateField('features', c ? [...formData.features, f] : formData.features.filter(x => x !== f))}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {step === 4 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Comments</Heading>
            <TextArea 
              label="Additional Comments" 
              value={formData.comments} 
              onChange={(v) => updateField('comments', v)} 
              maxLength={500} 
              showCount 
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Review</Heading>
            <Card padding="var(--ggui-spacing-4)">
              <Stack gap="var(--ggui-spacing-2)">
                <Text><strong>Name:</strong> {formData.name}</Text>
                <Text><strong>Email:</strong> {formData.email}</Text>
                <Text><strong>Satisfaction:</strong> {formData.satisfaction > 0 ? props.satisfactionLabels[formData.satisfaction - 1] : 'Not selected'}</Text>

                <Text><strong>Features:</strong> {formData.features.join(', ')}</Text>
                <Text><strong>Comments:</strong> {formData.comments || 'None'}</Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Row justify="between" gap="var(--ggui-spacing-2)">
        <Row justify="between" gap="var(--ggui-spacing-2)">
          {step > 1 ? (
            <Button as={Clickable} variant="outline" onClick={handleBack}>Back</Button>
          ) : <div />}
          {step < 5 ? (
            <Button as={Clickable} onClick={handleNext} disabled={!isStepValid}>Next</Button>
          ) : (
            <Button as={Clickable} variant="primary" onClick={handleSubmit}>Submit</Button>
          )}
        </Row>


      </Stack>
    </Container>
  );


}

