import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




const TaskCard = (props: { 
  task: any, 
  columns: any[], 
  onMove: (taskId: string, column: string) => void,
  onEdit: (taskId: string, newData: any) => void 
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [title, setTitle] = useState(props.task.title || '');
  const [dueDate, setDueDate] = useState(props.task.dueDate || '');

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" as={Clickable} onDoubleClick={() => setIsEditing(true)}>
      <Stack gap="var(--ggui-spacing-2)">
        {isEditing ? (
          <>
            <Input label="Title" value={title} onChange={setTitle} />
            <Input label="Due Date" value={dueDate} onChange={setDueDate} />
            <Button size="sm" as={Clickable} onClick={() => { setIsEditing(false); props.onEdit(props.task.id, { title, dueDate }); }}>Save</Button>
          </>
        ) : (
          <>
            <Heading level={6}>{props.task.title}</Heading>
            {props.task.dueDate && <Text size="sm" color="var(--ggui-color-text-secondary)">Due: {props.task.dueDate}</Text>}
          </>
        )}
        <Row justify="between" align="center">
          <Badge variant="default" size="sm">{props.task.priority}</Badge>
          <Avatar name={props.task.assignee || '??'} size={24} />
        </Row>
        <Select 
          label="Move to" 
          value={props.task.column} 
          onChange={(val) => props.onMove(props.task.id, val)}
          options={props.columns.map(c => ({ value: c.id, label: c.name }))}
        />
      </Stack>
    </Card>
  );
};



export default function Component(props: Props) {
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  const [localTasks, setLocalTasks] = useState(props.tasks || []);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'delete') {
        setLocalTasks(prev => prev.filter(t => t.id !== task?.id));
      } else if (task) {
        setLocalTasks(prev => {
          const idx = prev.findIndex(t => t.id === task.id);
          if (idx > -1) {
            const next = [...prev];
            next[idx] = task;
            return next;
          }
          return [...prev, task];
        });
      }
    }
  }, [taskChanged.latest]);

  const handleMove = useCallback((taskId: string, column: string) => {
    taskUpdate({ action: 'move', taskId, data: { column } });
  }, [taskUpdate]);

  const handleAdd = useCallback((columnId: string) => {
    const newTask = { id: Date.now().toString(), title: newTaskTitle, column: columnId, priority: newTaskPriority, dueDate: newTaskDueDate };
    taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } as any });
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setNewTaskDueDate('');
    setAddingTo(null);
  }, [newTaskTitle, newTaskPriority, newTaskDueDate, taskUpdate]);



  const stats = useMemo(() => {
    const total = localTasks.length;
    const done = localTasks.filter(t => t.column === 'done').length;
    return { total, done };
  }, [localTasks]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Row justify="between">
          <Heading level={1}>Task Board</Heading>
          <Row gap="var(--ggui-spacing-4)">
            <Badge variant="info">Total: {stats.total}</Badge>
            <Badge variant="success">Completed: {stats.done}</Badge>
          </Row>
        </Row>

        <Row gap="var(--ggui-spacing-4)" align="stretch">
          {props.columns.map(col => (
            <Box key={col.id} padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)" style={{ flex: 1 }}>
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>{col.name} ({localTasks.filter(t => t.column === col.id).length})</Heading>
                <Stack gap="var(--ggui-spacing-3)">
                  {localTasks.filter(t => t.column === col.id).map(t => (
                    <TaskCard key={t.id} task={t} columns={props.columns} onMove={handleMove} onEdit={(id, data) => taskUpdate({ action: 'edit', taskId: id, data })} />
                  ))}
                </Stack>
                {addingTo === col.id ? (
                  <Card padding="var(--ggui-spacing-3)">
                    <Input label="New Task Title" value={newTaskTitle} onChange={setNewTaskTitle} />
                    <Select label="Priority" value={newTaskPriority} onChange={(v: any) => setNewTaskPriority(v)} options={[{label: 'Low', value: 'low'}, {label: 'Medium', value: 'medium'}, {label: 'High', value: 'high'}]} />
                    <Input label="Due Date" value={newTaskDueDate} onChange={setNewTaskDueDate} />
                    <Box padding="var(--ggui-spacing-2) 0 0 0">
                      <Row gap="var(--ggui-spacing-2)">
                        <Button size="sm" as={Clickable} onClick={() => handleAdd(col.id)}>Add</Button>
                        <Button size="sm" variant="ghost" as={Clickable} onClick={() => setAddingTo(null)}>Cancel</Button>
                      </Row>
                    </Box>
                  </Card>
                ) : (
                  <Button variant="outline" size="sm" as={Clickable} onClick={() => setAddingTo(col.id)}>+ Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );

}

