// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





const CATEGORY_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-primary-300)',
  'alkaline-earth-metal': 'var(--ggui-color-primary-200)',
  'transition-metal': 'var(--ggui-color-primary-400)',
  'post-transition-metal': 'var(--ggui-color-primary-500)',
  'metalloid': 'var(--ggui-color-success-400)',
  'nonmetal': 'var(--ggui-color-success-300)',
  'halogen': 'var(--ggui-color-warning-300)',
  'noble-gas': 'var(--ggui-color-info-300)',
  'lanthanide': 'var(--ggui-color-error-300)',
  'actinide': 'var(--ggui-color-error-400)',
};

const DEFAULT_COLOR = 'var(--ggui-color-surfaceVariant)';

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  const filteredElements = useMemo(() => {
    const elements = props.elements || [];
    if (!searchTerm) return elements;
    const term = searchTerm.toLowerCase();
    return elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(term) ||
        e.symbol?.toLowerCase().includes(term)
    );
  }, [props.elements, searchTerm]);

  const categories = useMemo(() => {
    const cats = new Set((props.elements || []).map((e) => e.category || 'unknown'));
    return Array.from(cats);
  }, [props.elements]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={1}>Periodic Table</Heading>

        <Input 
          label="Search Elements" 
          placeholder="Enter name or symbol..." 
          value={searchTerm} 
          onChange={(val) => setSearchTerm(val)} 
        />

        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1)' }}>
          {(props.elements || []).map((el) => {
            const isMatch = filteredElements.includes(el);
            const color = el.category ? CATEGORY_COLORS[el.category.replace(/\s+/g, '-').toLowerCase()] || DEFAULT_COLOR : DEFAULT_COLOR;

            return (
              <Box
                key={el.atomicNumber}
                as={Clickable}
                onClick={() => setSelectedElement(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  aspectRatio: '1',
                  opacity: isMatch ? 1 : 0.2,
                  transition: 'opacity 0.2s',
