                    <Text size="2xl">{opt}</Text>
                  </Box>

                ))}
              </Row>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Select label="Role" value={formData.role} onChange={(v: string) => setFormData({ ...formData, role: v })} options={props.roleOptions.map((r) => ({ value: r, label: r }))} />
              <Row justify="between" align="center" as="label">
                <Text>Enable Email Notifications</Text>
                <Toggle checked={formData.emailNotifications} onChange={(c: boolean) => setFormData({ ...formData, emailNotifications: c })} />
              </Row>
              <Row justify="between" align="center" as="label">
                <Text>Dark Mode</Text>
                <Toggle checked={formData.theme === 'dark'} onChange={(c: boolean) => setFormData({ ...formData, theme: c ? 'dark' : 'light' })} />
              </Row>
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Review Your Profile</Heading>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Avatar: {formData.avatar}</Text>
              <Text>Role: {formData.role}</Text>
              <Text>Notifications: {formData.emailNotifications ? 'On' : 'Off'}</Text>
              <Text>Theme: {formData.theme}</Text>
            </Stack>
          )}
        </Card>

        <Row gap="var(--ggui-spacing-2)" justify="end">
          {step > 1 && <Button as={Clickable} variant="outline" onClick={handleBack}>Back</Button>}
          {step < 3 ? (
            <Button as={Clickable} disabled={(step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid)} onClick={handleNext}>Next</Button>
          ) : (
            <Button as={Clickable} variant="primary" onClick={handleSubmit}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
